import { useDocumentHead } from "../lib/useDocumentHead.js";
import { useRouteScrollContext } from "../lib/useRouteScrollContext.js";
import StubSection from "./StubSection.jsx";
import { SEO } from "../data/seo.js";
import { PROCESS } from "../data/process.js";
import { TEAM } from "../data/team.js";
import { LINKS } from "../data/links.js";

// Studio STUB. Owns: #process (4-step axis rail, S08) and #team (18 members —
// all 18 LinkedIn member URLs render here so verify/facts_check see 18). No 3D
// on this route (zero `three` bytes — DIRECTION GL rules). S08 composes the
// real axis-rail + diagonal-stagger team grid + manifesto.
export default function Studio() {
  useDocumentHead(SEO["/studio"]);
  // Route-scoped trigger context (scar #9) — S08 registers triggers via add().
  const { scopeRef } = useRouteScrollContext();

  return (
    <div ref={scopeRef}>
      <StubSection id="process" eyebrow="How we build" title="Four steps, no slices">
        <ol className="grid gap-6 md:grid-cols-2">
          {PROCESS.map((p) => (
            <li key={p.num} className="rounded-md border border-line bg-surface p-6">
              <span className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
                {p.num}
              </span>
              <h3 className="mt-2 font-display text-title font-semibold text-ink">{p.title}</h3>
              <p className="mt-3 font-body text-small text-ink-dim">{p.description}</p>
            </li>
          ))}
        </ol>
      </StubSection>

      <StubSection id="team" eyebrow="Who builds it" title="The team">
        <ul className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {TEAM.map((m) => (
            <li key={m.slug} className="rounded-md border border-line bg-surface p-5">
              <p className="font-display text-base font-semibold text-ink">{m.name}</p>
              <p className="mt-1 font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
                {m.category}
                {m.specialty ? ` · ${m.specialty}` : ""}
              </p>
              <a
                href={m.linkedin}
                target="_blank"
                rel="noopener noreferrer"
                className="mt-3 inline-block font-body text-small text-ink underline decoration-accent underline-offset-4 hover:text-accent"
              >
                LinkedIn
              </a>
            </li>
          ))}
        </ul>
      </StubSection>

      <StubSection id="manifesto" eyebrow="Manifesto" title="No fluff. Things that work.">
        <p className="max-w-2xl font-body text-ink-dim">
          We learn the domain before we write code, ship the whole thing, then
          measure and iterate. Honest about what AI can and can't do.
        </p>
        <a
          href={LINKS.calendly}
          target="_blank"
          rel="noopener noreferrer"
          className="mt-6 inline-block rounded-sm bg-accent px-5 py-3 font-body text-sm font-medium text-ground transition-colors hover:brightness-110"
        >
          Book a call
        </a>
      </StubSection>
    </div>
  );
}

