1	/**
2	 * AxisRail — pinned lateral rail (DIRECTION: horizontal-pin showpiece, S04).
3	 *
4	 * Pins its root and translates a flex-row track of full-viewport panels
5	 * sideways as you scroll vertically — the canonical "scroll down, move across"
6	 * scene. Each direct child is one panel and fills one viewport-width slice of
7	 * the rail.
8	 *
9	 * Props:
10	 *   children   each child = one panel (n panels → track is n*100% wide).
11	 *   markers    render the thin top progress rail + accent bar + counter
12	 *              (default true). The bar/counter are transform/textContent only.
13	 *   className  extra classes on the root.
14	 *   id         optional DOM id.
15	 *
16	 * Gate: scar #8 static — when useMotionStatic() is true panels STACK vertically
17	 * (flex-col, gap), each full-width and readable, no pin, no rail animation, no
18	 * horizontal motion; data-static="true". Reduced/mobile users read every panel
19	 * top-to-bottom as plain blocks.
20	 *
21	 * Scars: #4 (root is `relative`, hosts the absolute marker rail),
22	 * #5 (onLeave/onLeaveBack latch the timeline to progress 1/0 so a fling never
23	 *     strands the rail mid-slide; data-latched records which edge),
24	 * #7 (the counter is precomputed once into a label array; onUpdate snaps an
25	 *     index and writes textContent only on change — zero per-frame allocation,
26	 *     no per-frame rect reads),
27	 * #8 (static stack).
28	 *
29	 * Alias: `HorizontalPin` re-exports AxisRail (the DIRECTION name).
30	 */
31	import { Children, useLayoutEffect, useMemo, useRef } from "react";
32	import { gsap } from "gsap";
33	import { ScrollTrigger } from "gsap/ScrollTrigger";
34	import { EASE, DUR } from "../../lib/motion.js";
35	import { useMotionStatic } from "./useMotionStatic.js";
36	
37	gsap.registerPlugin(ScrollTrigger);
38	
39	function pad2(n) {
40	  return n < 10 ? `0${n}` : `${n}`;
41	}
42	
43	function AxisRail({ children, markers = true, className = "", id }) {
44	  const rootRef = useRef(null);
45	  const trackRef = useRef(null);
46	  const barRef = useRef(null);
47	  const counterRef = useRef(null);
48	  const isStatic = useMotionStatic();
49	
50	  const panels = useMemo(() => Children.toArray(children), [children]);
51	  const n = panels.length;
52	
53	  // Precompute counter label strings ONCE (scar #7 — no per-frame string work).
54	  const labels = useMemo(
55	    () => panels.map((_, i) => `${pad2(i + 1)} / ${pad2(n)}`),
56	    [panels, n]
57	  );
58	
59	  useLayoutEffect(() => {
60	    if (isStatic || n === 0) return undefined;
61	    const root = rootRef.current;
62	    const track = trackRef.current;
63	    if (!root || !track) return undefined;
64	
65	    const ctx = gsap.context(() => {
66	      const bar = barRef.current;
67	      const counter = counterRef.current;
68	      let lastIndex = -1;
69	
70	      const tl = gsap.timeline({
71	        scrollTrigger: {
72	          trigger: root,
73	          start: "top top",
74	          end: `+=${(n - 1) * 100}%`,
75	          pin: root,
76	          anticipatePin: 1,
77	          scrub: 0.6,
78	          invalidateOnRefresh: true,
79	          // Counter snap: derive panel index from progress, write only on
80	          // change. No allocations, no rect reads.
81	          onUpdate: (self) => {
82	            if (!counter) return;
83	            const idx = Math.min(n - 1, Math.round(self.progress * (n - 1)));
84	            if (idx !== lastIndex) {
85	              lastIndex = idx;
86	              counter.textContent = labels[idx];
87	            }
88	          },
89	          // Scar #5 — fling past an edge commits the rail to that boundary.
90	          // overwrite MUST be "auto", never true: the latch targets the
91	          // timeline, and `true` kills ALL tweens of that target — including
92	          // ScrollTrigger's internal scrub tween (it animates totalProgress),
93	          // permanently freezing the rail after the first leave. "auto" kills
94	          // only conflicting `progress` tweens (prior latches). Found by the
95	          // S07 travel assertion.
96	          onLeave: () => {
97	            gsap.to(tl, {
98	              progress: 1,
99	              duration: DUR.XS,
100	              ease: EASE.SETTLE,
101	              overwrite: "auto",
102	            });
103	            root.setAttribute("data-latched", "end");
104	          },
105	          onLeaveBack: () => {
106	            gsap.to(tl, {
107	              progress: 0,
108	              duration: DUR.XS,
109	              ease: EASE.SETTLE,
110	              overwrite: "auto",
111	            });
112	            root.setAttribute("data-latched", "start");
113	          },
114	        },
115	      });
116	
117	      // Track slides left by (n-1)/n of its own width (each panel is 1/n of
118	      // the n*100% track). Linear scrub — ease "none".
119	      tl.to(track, { xPercent: -100 * ((n - 1) / n), ease: "none" }, 0);
120	
121	      // Accent progress bar shares the SAME timeline (transform only).
122	      if (bar) tl.fromTo(bar, { scaleX: 0 }, { scaleX: 1, ease: "none" }, 0);
123	
124	      if (counter) counter.textContent = labels[0];
125	    }, root);
126	
127	    return () => ctx.revert();
128	  }, [isStatic, n, labels]);
129	
130	  // ---- static tier: stacked, readable, no motion. --------------------------
131	  if (isStatic) {
132	    return (
133	      <div
134	        ref={rootRef}
135	        id={id}
136	        data-axis-rail=""
137	        data-static="true"
138	        className={`relative flex flex-col gap-10 ${className}`}
139	      >
140	        {panels.map((panel, i) => (
141	          <div key={i} className="w-full">
142	            {panel}
143	          </div>
144	        ))}
145	      </div>
146	    );
147	  }
148	
149	  // ---- motion tier: pinned rail. -------------------------------------------
150	  return (
151	    <div
152	      ref={rootRef}
153	      id={id}
154	      data-axis-rail=""
155	      className={`relative overflow-hidden ${className}`}
156	    >
157	      {markers && (
158	        <div className="absolute inset-x-0 top-0 z-10 flex items-center gap-4 px-[clamp(1.25rem,4vw,3rem)] py-3">
159	          <div className="relative h-px flex-1 bg-line">
160	            <div
161	              ref={barRef}
162	              className="absolute inset-y-0 left-0 w-full origin-left bg-accent"
163	              style={{ transform: "scaleX(0)" }}
164	              aria-hidden="true"
165	            />
166	          </div>
167	          <span
168	            ref={counterRef}
169	            className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted"
170	            aria-hidden="true"
171	          >
172	            {labels[0]}
173	          </span>
174	        </div>
175	      )}
176	      <div
177	        ref={trackRef}
178	        className="flex"
179	        style={{ width: `${n * 100}%` }}
180	      >
181	        {panels.map((panel, i) => (
182	          <div key={i} className="w-full shrink-0">
183	            {panel}
184	          </div>
185	        ))}
186	      </div>
187	    </div>
188	  );
189	}
190	
191	export default AxisRail;
192	export { AxisRail };
193	export const HorizontalPin = AxisRail;
