/**
 * AxisRail — pinned lateral rail (DIRECTION: horizontal-pin showpiece, S04).
 *
 * Pins its root and translates a flex-row track of full-viewport panels
 * sideways as you scroll vertically — the canonical "scroll down, move across"
 * scene. Each direct child is one panel and fills one viewport-width slice of
 * the rail.
 *
 * Props:
 *   children   each child = one panel (n panels → track is n*100% wide).
 *   markers    render the thin top progress rail + accent bar + counter
 *              (default true). The bar/counter are transform/textContent only.
 *   className  extra classes on the root.
 *   id         optional DOM id.
 *
 * Gate: scar #8 static — when useMotionStatic() is true panels STACK vertically
 * (flex-col, gap), each full-width and readable, no pin, no rail animation, no
 * horizontal motion; data-static="true". Reduced/mobile users read every panel
 * top-to-bottom as plain blocks.
 *
 * Scars: #4 (root is `relative`, hosts the absolute marker rail),
 * #5 (onLeave/onLeaveBack latch the timeline to progress 1/0 so a fling never
 *     strands the rail mid-slide; data-latched records which edge),
 * #7 (the counter is precomputed once into a label array; onUpdate snaps an
 *     index and writes textContent only on change — zero per-frame allocation,
 *     no per-frame rect reads),
 * #8 (static stack).
 *
 * Alias: `HorizontalPin` re-exports AxisRail (the DIRECTION name).
 */
import { Children, useLayoutEffect, useMemo, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { EASE, DUR } from "../../lib/motion.js";
import { useMotionStatic } from "./useMotionStatic.js";

gsap.registerPlugin(ScrollTrigger);

function pad2(n) {
  return n < 10 ? `0${n}` : `${n}`;
}

function AxisRail({ children, markers = true, className = "", id }) {
  const rootRef = useRef(null);
  const trackRef = useRef(null);
  const barRef = useRef(null);
  const counterRef = useRef(null);
  const isStatic = useMotionStatic();

  const panels = useMemo(() => Children.toArray(children), [children]);
  const n = panels.length;

  // Precompute counter label strings ONCE (scar #7 — no per-frame string work).
  const labels = useMemo(
    () => panels.map((_, i) => `${pad2(i + 1)} / ${pad2(n)}`),
    [panels, n]
  );

  useLayoutEffect(() => {
    if (isStatic || n === 0) return undefined;
    const root = rootRef.current;
    const track = trackRef.current;
    if (!root || !track) return undefined;

    const ctx = gsap.context(() => {
      const bar = barRef.current;
      const counter = counterRef.current;
      let lastIndex = -1;

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: root,
          start: "top top",
          end: `+=${(n - 1) * 100}%`,
          pin: root,
          anticipatePin: 1,
          scrub: 0.6,
          invalidateOnRefresh: true,
          // Counter snap: derive panel index from progress, write only on
          // change. No allocations, no rect reads.
          onUpdate: (self) => {
            if (!counter) return;
            const idx = Math.min(n - 1, Math.round(self.progress * (n - 1)));
            if (idx !== lastIndex) {
              lastIndex = idx;
              counter.textContent = labels[idx];
            }
          },
          // Scar #5 — fling past an edge commits the rail to that boundary.
          // overwrite MUST be "auto", never true: the latch targets the
          // timeline, and `true` kills ALL tweens of that target — including
          // ScrollTrigger's internal scrub tween (it animates totalProgress),
          // permanently freezing the rail after the first leave. "auto" kills
          // only conflicting `progress` tweens (prior latches). Found by the
          // S07 travel assertion.
          onLeave: () => {
            gsap.to(tl, {
              progress: 1,
              duration: DUR.XS,
              ease: EASE.SETTLE,
              overwrite: "auto",
            });
            root.setAttribute("data-latched", "end");
          },
          onLeaveBack: () => {
            gsap.to(tl, {
              progress: 0,
              duration: DUR.XS,
              ease: EASE.SETTLE,
              overwrite: "auto",
            });
            root.setAttribute("data-latched", "start");
          },
        },
      });

      // Track slides left by (n-1)/n of its own width (each panel is 1/n of
      // the n*100% track). Linear scrub — ease "none".
      tl.to(track, { xPercent: -100 * ((n - 1) / n), ease: "none" }, 0);

      // Accent progress bar shares the SAME timeline (transform only).
      if (bar) tl.fromTo(bar, { scaleX: 0 }, { scaleX: 1, ease: "none" }, 0);

      if (counter) counter.textContent = labels[0];
    }, root);

    return () => ctx.revert();
  }, [isStatic, n, labels]);

  // ---- static tier: stacked, readable, no motion. --------------------------
  if (isStatic) {
    return (
      <div
        ref={rootRef}
        id={id}
        data-axis-rail=""
        data-static="true"
        className={`relative flex flex-col gap-10 ${className}`}
      >
        {panels.map((panel, i) => (
          <div key={i} className="w-full">
            {panel}
          </div>
        ))}
      </div>
    );
  }

  // ---- motion tier: pinned rail. -------------------------------------------
  return (
    <div
      ref={rootRef}
      id={id}
      data-axis-rail=""
      className={`relative overflow-hidden ${className}`}
    >
      {markers && (
        <div className="absolute inset-x-0 top-0 z-10 flex items-center gap-4 px-[clamp(1.25rem,4vw,3rem)] py-3">
          <div className="relative h-px flex-1 bg-line">
            <div
              ref={barRef}
              className="absolute inset-y-0 left-0 w-full origin-left bg-accent"
              style={{ transform: "scaleX(0)" }}
              aria-hidden="true"
            />
          </div>
          <span
            ref={counterRef}
            className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted"
            aria-hidden="true"
          >
            {labels[0]}
          </span>
        </div>
      )}
      <div
        ref={trackRef}
        className="flex"
        style={{ width: `${n * 100}%` }}
      >
        {panels.map((panel, i) => (
          <div key={i} className="w-full shrink-0">
            {panel}
          </div>
        ))}
      </div>
    </div>
  );
}

export default AxisRail;
export { AxisRail };
export const HorizontalPin = AxisRail;

