 * drifts relative to the page. Negative `speed` = counter-scroll (moves against
 * the page). Linear scrub (ease "none") — a parallax must track scroll 1:1.
 *
 * Travel note: total travel ≈ |speed| * 600px (fromTo +speed*300 → -speed*300).
 * For the default speed -0.15 that's ~90px — comfortably above TRAVEL (40), so
 * the drift reads as a deliberate move, not a glitch. Keep |speed| ≳ 0.07 to
 * stay perceptible.
 *
 * Props:
 *   speed     parallax factor (default -0.15; negative = counter-scroll).
 *   axis      "y" (default) or "x" — which axis drifts.
 *   trigger   "self" (default — the layer's own pass) or "parent" (the parent
 *             element's pass; resolved as root.parentElement in the effect).
 *   className extra classes on the root.
 *   children  the parallaxed content.
 *   as        root element tag (default "div").
 *
 * Gate: scar #8 static — when useMotionStatic() is true children render plain
 * with no transform, data-static="true". Reduced/mobile users see a still
 * layer in its resting position.
 *
 * Scars: #7 (single scrubbed tween; no per-frame work in JS),
 * #8 (static = no transform).
 */
import { createElement, useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useMotionStatic } from "./useMotionStatic.js";

gsap.registerPlugin(ScrollTrigger);

function ParallaxLayer({
  speed = -0.15,
  axis = "y",
  trigger = "self",
  className = "",
  children,
  as = "div",
}) {
  const rootRef = useRef(null);
  const isStatic = useMotionStatic();

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const root = rootRef.current;
    if (!root) return undefined;

    const ctx = gsap.context(() => {
      const triggerEl =
        trigger === "parent" ? root.parentElement || root : root;
      const prop = axis === "x" ? "x" : "y";
      const amt = speed * 300;

      gsap.fromTo(
        root,
        { [prop]: amt },
        {
          [prop]: -amt,
          ease: "none",
          scrollTrigger: {
            trigger: triggerEl,
            start: "top bottom",
            end: "bottom top",
            scrub: true,
            invalidateOnRefresh: true,
          },
        }
      );
    }, root);

    return () => ctx.revert();
  }, [isStatic, speed, axis, trigger]);

  return createElement(
    as,
    {
      ref: rootRef,
      "data-parallax-layer": "",
      "data-static": isStatic ? "true" : undefined,
      className,
    },
    children
  );
}

export default ParallaxLayer;
export { ParallaxLayer };

