/**
 * KineticMarquee — velocity-coupled marquee (DIRECTION "KineticMarquee").
 * THE single consumer of scrollBus this sprint.
 *
 * A whitespace-nowrap track holds the item row TWICE (second copy aria-hidden)
 * and drifts left at `speed` px/s, plus |scrollBus.velocity|*velocityFactor of
 * extra drift in the SAME direction as the scroll sign — deterministic, base
 * drift never reverses. Offset wraps modulo the single-copy row width (cached
 * on mount + debounced resize, never per frame) and is written via one
 * quickSetter x. A root ScrollTrigger (onToggle) flips an `active` flag so the
 * ticker only writes while on-screen (it does NOT kill anything in onToggle).
 *
 * Props:
 *   items           string[]  (required) the marquee tokens.
 *   speed           number    40    base leftward drift, px/s.
 *   velocityFactor  number    0.1   extra drift per px/s of scroll velocity.
 *   skewOnVelocity  boolean   false the ONE allowed velocity-skew (default OFF).
 *   className       string    ""    passthrough to the root.
 *   renderItem      fn        —     optional item=>node (else the chip idiom).
 *
 * Chip idiom (default renderItem): rounded-sm border border-line px-3 py-1
 * font-mono text-[0.8125rem] text-ink-dim.
 *
 * Gate (scar #8): useMotionStatic() ⇒ a flex-wrap list of the items (each chip
 * fully visible, no duplication, no overflow, no horizontal motion),
 * data-static="true", zero GSAP / zero scrollBus subscription.
 *
 * Reduced/mobile fallback: the static flex-wrap list above (fully readable).
 *
 * Scars: #1 — onToggle only flips a boolean, never kills (no synchronous kill).
 * #4 — the root hosts no absolute inset-0 child; still marked relative for the
 * overflow-hidden frame. #5 n/a (not a scrubbed scene — a continuous drift; no
 * half-scrubbed state to strand). #7 — one gsap.ticker callback, zero per-frame
 * allocations (mutates `offset`, reads cached rowWidth + scrollBus.velocity,
 * no getBoundingClientRect per frame, no setState in the loop). All GSAP inside
 * the component's own gsap.context; cleanup removes ticker, unsubscribes the
 * bus, removes the resize listener, reverts (StrictMode idempotent — subscribe/
 * unsubscribe pairs balance via scrollBus refcount).
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useMotionStatic } from "./useMotionStatic.js";
import { scrollBus, subscribeScrollBus } from "../../lib/scrollBus.js";

gsap.registerPlugin(ScrollTrigger);

function defaultChip(item) {
  return (
    <span className="rounded-sm border border-line px-3 py-1 font-mono text-[0.8125rem] text-ink-dim">
      {item}
    </span>
  );
}

function clamp(n, lo, hi) {
  return n < lo ? lo : n > hi ? hi : n;
}

function KineticMarquee({
  items,
  speed = 40,
  velocityFactor = 0.1,
  skewOnVelocity = false,
  className = "",
  renderItem,
}) {
  const isStatic = useMotionStatic();
  const rootRef = useRef(null);
  const trackRef = useRef(null);
  const rowRef = useRef(null);

  const render = renderItem || defaultChip;

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const root = rootRef.current;
    const track = trackRef.current;
    const row = rowRef.current;
    if (!root || !track || !row) return undefined;

    const ctx = gsap.context(() => {
      const unsubscribe = subscribeScrollBus();
      const setX = gsap.quickSetter(track, "x", "px");
      const setSkew = skewOnVelocity
        ? gsap.quickSetter(track, "skewX", "deg")
        : null;

      // Cached on mount + debounced resize — never measured per frame.
      let rowWidth = row.offsetWidth || 1;
      let offset = 0;
      let active = true;
      let resizeCall = null;

      const measure = () => {
        rowWidth = row.offsetWidth || 1;
      };
      const onResize = () => {
        if (resizeCall) resizeCall.kill();
        resizeCall = gsap.delayedCall(0.2, measure);
      };

      function tick(_time, deltaTime) {
        if (!active) return;
        const dt = Math.min(deltaTime, 64) / 1000;
        const v = scrollBus.velocity;
        const sign = v === 0 ? 1 : Math.sign(v);
        // Base drift always leftward; |velocity| adds extra in the scroll sign.
        const extra = Math.min(Math.abs(v), 4000) * velocityFactor * sign;
        offset -= (speed + extra) * dt;
        // Wrap into [-rowWidth, 0] so the second copy fills the seam.
        offset = ((offset % rowWidth) + rowWidth) % rowWidth - rowWidth;
        setX(offset);
        if (setSkew) setSkew(clamp(v * 0.003, -6, 6));
      }

      // onToggle only flips `active` (scar #1 — never kill here).
      const st = ScrollTrigger.create({
        trigger: root,
        start: "top bottom",
        end: "bottom top",
        onToggle: (self) => {
          active = self.isActive;
        },
      });
      active = st.isActive;

      window.addEventListener("resize", onResize);
      gsap.ticker.add(tick);

      return () => {
        gsap.ticker.remove(tick);
        window.removeEventListener("resize", onResize);
        if (resizeCall) resizeCall.kill();
        unsubscribe();
      };
    }, rootRef);

    return () => ctx.revert();
  }, [isStatic, speed, velocityFactor, skewOnVelocity]);

  const ariaLabel = Array.isArray(items) ? items.join(", ") : undefined;

  if (isStatic) {
    return (
      <div
        ref={rootRef}
        data-kinetic-marquee
        data-static="true"
        className={`flex flex-wrap gap-3 ${className}`.trim()}
      >
        {items.map((item, i) => (
          <span key={`${item}-${i}`}>{render(item)}</span>
        ))}
      </div>
    );
  }

  return (
    <div
      ref={rootRef}
      data-kinetic-marquee
      role="img"
      aria-label={ariaLabel}
      className={`relative overflow-hidden ${className}`.trim()}
    >
      <div
        ref={trackRef}
        className="inline-flex whitespace-nowrap will-change-transform"
        aria-hidden="true"
      >
        <div ref={rowRef} className="inline-flex shrink-0 gap-3 pr-3">
          {items.map((item, i) => (
            <span key={`a-${item}-${i}`}>{render(item)}</span>
          ))}
        </div>
        <div className="inline-flex shrink-0 gap-3 pr-3" aria-hidden="true">
          {items.map((item, i) => (
            <span key={`b-${item}-${i}`}>{render(item)}</span>
          ))}
        </div>
      </div>
    </div>
  );
}

export default KineticMarquee;
export { KineticMarquee };

/**
 * W2 — Industry-solutions skyline (Work) — the [data-showpiece="skyline"] act.
 *
 * ============================== S12 CONTRACT ===============================
 * - Mount: [data-showpiece="skyline"] (below), position:relative. S12 MAY
 *   attach the instanced GL extrude as an `absolute inset-0` child of this
 *   mount — ONE instanced draw (instanceMatrix/instanceColor, never 9 meshes,
 *   <= 40 draw calls), lazy chunk only, desktop full tier only.
 * - Data binding: the 9 cards bind src/data/industries.js (INDUSTRIES — 9 of
 *   {industry,stat,subtitle,before,result,after}). Each card root carries
 *   data-industry="<slug>" so GL instances map 1:1 to cards.
 * - THE DOM card-field below ([data-skyline-field]) IS the lite/none design:
 *   reduced-motion + mobile render it static with before/after both shown and
 *   final stat numbers (scar #8 — never a blank). S12 must KEEP it as the
 *   fallback and gate the canvas off it, not replace it.
 * - Any pin/scrub S12 adds registers via useRouteScrollContext().add()
 *   (scar #9) with a scar-#5 latch; ZERO `three` bytes on lite/none tiers.
 * ===========================================================================
 *
 * This sprint is pure DOM/GSAP (no three imports anywhere on Work). Travel
 * vectors: the 9 volumes RISE (InkReveal from="up", diagonal stagger) while
 * each 3-card row counter-PANS horizontally (ParallaxLayer axis="x",
 * alternating direction per row — the field drifts like a panned drafting
 * sheet). Stats + result figures CountStrike to their locked values; the
 * non-numeric stats render static. Locked facts (9 names + 9 stats + 9
 * results) come from src/data/industries.js, never hand-typed.
 */
import { INDUSTRIES } from "../../data/industries.js";
import {
  Section,
  SectionHeader,
  InkReveal,
  ParallaxLayer,
  CountStrike,
} from "../../components/motion/index.js";

function slugify(s) {
  return s
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "");
}

/**
 * Numeric-leading figures count-strike to their exact locked string
 * ("98% defect-free output" → to=98, suffix="% defect-free output");
 * non-numeric figures ("Real-time fraud detection") render static.
 * The DOM always ships the final verbatim string either way.
 */
function Figure({ value, className = "", start }) {
  const m = /^(\d+(?:\.\d+)?)(.*)$/.exec(value);
  if (!m) return <span className={className}>{value}</span>;
  const decimals = (m[1].split(".")[1] || "").length;
  return (
    <CountStrike
      to={parseFloat(m[1])}
      decimals={decimals}
      suffix={m[2]}
      start={start}
      className={className}
    />
  );
}

// 3 rows × 3 volumes — the row is the pan unit, the card is the rise unit.
const ROWS = [INDUSTRIES.slice(0, 3), INDUSTRIES.slice(3, 6), INDUSTRIES.slice(6, 9)];

export default function SkylineField() {
  return (
    <Section id="industries" bordered className="overflow-x-clip">
      <SectionHeader
        eyebrow="Industry solutions"
        title="Nine verticals, drafted to spec."
        lead="Every agent ships with the before-state it replaces, a measured result, and the after-state it runs. The numbers are the design."
      />
      <div data-showpiece="skyline" className="relative mt-12">
        <div data-skyline-field="" className="flex flex-col gap-6">
          {ROWS.map((row, r) => (
            <ParallaxLayer
              key={r}
              axis="x"
              speed={r % 2 === 0 ? -0.09 : 0.09}
              className="will-change-transform"
            >
              <ul className="grid gap-6 md:grid-cols-3">
                {row.map((a, i) => (
                  <InkReveal
                    as="li"
                    key={a.industry}
                    from="up"
                    delay={i * 0.07 + r * 0.04}
                    data-industry={slugify(a.industry)}
                    className="flex flex-col rounded-md border border-line bg-surface p-7"
                  >
                    <p className="font-mono text-mono-label uppercase text-muted">
                      {a.industry}
                    </p>
                    <p className="mt-3 font-display text-title font-semibold leading-[1.15] text-accent">
                      <Figure value={a.stat} />
                    </p>
                    <p className="mt-2 font-body text-small text-ink-dim">
                      {a.subtitle}
                    </p>
                    <div className="mt-6 flex-1 border-t border-line pt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        before
                      </p>
                      <p className="mt-1.5 font-body text-small text-ink-dim">
                        {a.before}
                      </p>
                    </div>
                    <div className="mt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        result
                      </p>
                      {/* start "top 94%": the result line sits DEEP in the
                          card — with the default 80% a fully revealed card
                          would show the rewound 0 until the line itself
                          crossed 80% (caught by the S07 visual audit). */}
                      <p className="mt-1.5 font-display text-[1.375rem] font-semibold leading-snug text-ink">
                        <Figure value={a.result} start="top 94%" />
                      </p>
                    </div>
                    <div className="mt-5">
                      <p className="font-mono text-mono-label uppercase text-muted">
                        after
                      </p>
                      <p className="mt-1.5 font-body text-small text-ink-dim">
                        {a.after}
                      </p>
                    </div>
                  </InkReveal>
                ))}
              </ul>
            </ParallaxLayer>
          ))}
        </div>
      </div>
    </Section>
  );
}

