/**
 * Section / SectionHeader — the layout & rhythm primitive every page sprint
 * (S06–S13) composes. Deliberately STATIC: it owns no GSAP, no ScrollTrigger,
 * no reveal of its own. Page sprints wrap their content in InkReveal/SplitLines
 * themselves, so keeping Section animation-free decouples the layout tier from
 * the motion tier — Section never decides when content reveals.
 *
 * Section props:
 *   id        string   — anchor id forwarded to the root element.
 *   as        elem     — element/tag to render as (default "section").
 *   padded    bool     — when true, vertical section padding via the
 *                        --k-section-pad token (default true).
 *   bordered  bool     — when true, a bottom hairline (border-b border-line).
 *   className string   — merged onto the root, after the guaranteed utilities.
 *   children  node     — section body (placed inside the centered container).
 *   ...rest            — spread onto the root element.
 *
 * SectionHeader props:
 *   eyebrow   string   — optional mono micro-label above the title.
 *   title     string   — the h2 headline (required for a meaningful header).
 *   lead      string   — optional ink-dim supporting paragraph under the title.
 *   className string   — merged onto the header root.
 *
 * Gate: NONE. There is no motion to gate; Section renders identically on every
 * tier. It is the host other primitives reveal *inside*.
 *
 * Reduced / mobile fallback: identical to the default render (no motion path).
 *
 * Scar notes:
 *   - Scar #4: the root is ALWAYS `relative` so any absolute inset-0 child a
 *     page drops inside is positioned against the Section, not the viewport.
 *   - No injected <style>, token classes only (scar #8): text-ink / text-ink-dim
 *     / text-muted, border-line, font-display / font-mono. No accent here.
 */
import React from "react";

function cx(...parts) {
  return parts.filter(Boolean).join(" ");
}

export function Section({
  id,
  as: As = "section",
  padded = true,
  bordered = false,
  className,
  children,
  ...rest
}) {
  return (
    <As
      id={id}
      data-section=""
      className={cx("relative", bordered && "border-b border-line", className)}
      style={padded ? { paddingBlock: "var(--k-section-pad)" } : undefined}
      {...rest}
    >
      <div className="mx-auto max-w-[1280px] px-[clamp(1.25rem,4vw,3rem)]">
        {children}
      </div>
    </As>
  );
}

export function SectionHeader({ eyebrow, title, lead, className }) {
  return (
    <div data-section-header="" className={cx(className)}>
      {eyebrow ? (
        <p className="font-mono text-[0.6875rem] uppercase tracking-[0.12em] text-muted">
          {eyebrow}
        </p>
      ) : null}
      {title ? (
        <h2 className="mt-4 font-display text-[clamp(2.25rem,4.5vw,4rem)] font-semibold leading-[1.02] tracking-[-0.015em] text-ink">
          {title}
        </h2>
      ) : null}
      {lead ? (
        <p className="mt-5 max-w-2xl font-body text-ink-dim">{lead}</p>
      ) : null}
    </div>
  );
}

export default Section;

