1	/**
2	 * InkReveal — the ghost→inked strike. DIRECTION primitive "InkReveal".
3	 *
4	 * The element starts as a ghost (opacity 0, travelled TRAVEL px in the chosen
5	 * direction, plus a subtle clipPath inset wipe) and strikes once to its final
6	 * state on scroll, then holds forever (once:true — can never un-reveal).
7	 *
8	 * Props
9	 *   as        string   root tag (default "div")
10	 *   from      string   "up" | "left" | "right" | "none" — strike origin
11	 *                      (default "up"). "none" = pure fade, no travel/clip.
12	 *   delay     number   seconds before the strike (default 0)
13	 *   duration  number   strike duration seconds (default DUR.MD)
14	 *   start     string   ScrollTrigger start (default "top 82%")
15	 *   className string   passthrough classes for the root
16	 *   children           rendered content
17	 *   ...rest            spread onto the root element
18	 *
19	 * Gate (scar #8): useMotionStatic() === true ⇒ children rendered plain and
20	 * fully visible, zero GSAP, data-static="true" data-revealed="true".
21	 *
22	 * Reduced/mobile fallback: identical to the static tier.
23	 *
24	 * Scars:
25	 *   #1  no self.kill() in onUpdate — once:true cleans itself, nothing to defer.
26	 *   #2  EASE.PRIMARY only; clipPath/transform travel, opacity never on SNAP.
27	 *   #4  root carries "relative" (it may host absolute inset-0 children).
28	 *   #8  static tier = designed final state, zero GSAP.
29	 *  #12  the hidden initial gsap.set lives INSIDE the trigger's context, so a
30	 *       load already past `start` still reveals (once:true fires immediately).
31	 *  #13  data-revealed="true" stamped via setAttribute in onComplete (QA hook).
32	 */
33	import { useLayoutEffect, useRef } from "react";
34	import { gsap } from "gsap";
35	import { ScrollTrigger } from "gsap/ScrollTrigger";
36	import { EASE, DUR, TRAVEL } from "../../lib/motion.js";
37	import { useMotionStatic } from "./useMotionStatic.js";
38	
39	gsap.registerPlugin(ScrollTrigger);
40	
41	export function InkReveal({
42	  as: Tag = "div",
43	  from = "up",
44	  delay = 0,
45	  duration = DUR.MD,
46	  start = "top 82%",
47	  className,
48	  children,
49	  ...rest
50	}) {
51	  const isStatic = useMotionStatic();
52	  const rootRef = useRef(null);
53	
54	  useLayoutEffect(() => {
55	    if (isStatic) return undefined;
56	    const root = rootRef.current;
57	    if (!root) return undefined;
58	
59	    const ctx = gsap.context(() => {
60	      const initial = { opacity: 0 };
61	      const final = { opacity: 1 };
62	      if (from === "up") {
63	        initial.y = TRAVEL;
64	        final.y = 0;
65	      } else if (from === "left") {
66	        initial.x = -TRAVEL;
67	        final.x = 0;
68	      } else if (from === "right") {
69	        initial.x = TRAVEL;
70	        final.x = 0;
71	      }
72	      if (from !== "none") {
73	        // Tasteful directional wipe layered under the travel.
74	        if (from === "up") {
75	          initial.clipPath = "inset(35% 0% 0% 0%)";
76	        } else if (from === "left") {
77	          initial.clipPath = "inset(0% 35% 0% 0%)";
78	        } else if (from === "right") {
79	          initial.clipPath = "inset(0% 0% 0% 35%)";
80	        }
81	        final.clipPath = "inset(0% 0% 0% 0%)";
82	      }
83	
84	      gsap.set(root, initial);
85	      gsap.to(root, {
86	        ...final,
87	        ease: EASE.PRIMARY,
88	        duration,
89	        delay,
90	        scrollTrigger: {
91	          trigger: root,
