/**
 * InkReveal — the ghost→inked strike. DIRECTION primitive "InkReveal".
 *
 * The element starts as a ghost (opacity 0, travelled TRAVEL px in the chosen
 * direction, plus a subtle clipPath inset wipe) and strikes once to its final
 * state on scroll, then holds forever (once:true — can never un-reveal).
 *
 * Props
 *   as        string   root tag (default "div")
 *   from      string   "up" | "left" | "right" | "none" — strike origin
 *                      (default "up"). "none" = pure fade, no travel/clip.
 *   delay     number   seconds before the strike (default 0)
 *   duration  number   strike duration seconds (default DUR.MD)
 *   start     string   ScrollTrigger start (default "top 82%")
 *   className string   passthrough classes for the root
 *   children           rendered content
 *   ...rest            spread onto the root element
 *
 * Gate (scar #8): useMotionStatic() === true ⇒ children rendered plain and
 * fully visible, zero GSAP, data-static="true" data-revealed="true".
 *
 * Reduced/mobile fallback: identical to the static tier.
 *
 * Scars:
 *   #1  no self.kill() in onUpdate — once:true cleans itself, nothing to defer.
 *   #2  EASE.PRIMARY only; clipPath/transform travel, opacity never on SNAP.
 *   #4  root carries "relative" (it may host absolute inset-0 children).
 *   #8  static tier = designed final state, zero GSAP.
 *  #12  the hidden initial gsap.set lives INSIDE the trigger's context, so a
 *       load already past `start` still reveals (once:true fires immediately).
 *  #13  data-revealed="true" stamped via setAttribute in onComplete (QA hook).
 */
import { useLayoutEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { EASE, DUR, TRAVEL } from "../../lib/motion.js";
import { useMotionStatic } from "./useMotionStatic.js";

gsap.registerPlugin(ScrollTrigger);

export function InkReveal({
  as: Tag = "div",
  from = "up",
  delay = 0,
  duration = DUR.MD,
  start = "top 82%",
  className,
  children,
  ...rest
}) {
  const isStatic = useMotionStatic();
  const rootRef = useRef(null);

  useLayoutEffect(() => {
    if (isStatic) return undefined;
    const root = rootRef.current;
    if (!root) return undefined;

    const ctx = gsap.context(() => {
      const initial = { opacity: 0 };
      const final = { opacity: 1 };
      if (from === "up") {
        initial.y = TRAVEL;
        final.y = 0;
      } else if (from === "left") {
        initial.x = -TRAVEL;
        final.x = 0;
      } else if (from === "right") {
        initial.x = TRAVEL;
        final.x = 0;
      }
      if (from !== "none") {
        // Tasteful directional wipe layered under the travel.
        if (from === "up") {
          initial.clipPath = "inset(35% 0% 0% 0%)";
        } else if (from === "left") {
          initial.clipPath = "inset(0% 35% 0% 0%)";
        } else if (from === "right") {
          initial.clipPath = "inset(0% 0% 0% 35%)";
        }
        final.clipPath = "inset(0% 0% 0% 0%)";
      }

      gsap.set(root, initial);
      gsap.to(root, {
        ...final,
        ease: EASE.PRIMARY,
        duration,
        delay,
        scrollTrigger: {
          trigger: root,
          start,
          once: true,
        },
        onComplete: () => {
          root.setAttribute("data-revealed", "true");
        },
      });
    }, rootRef);

    return () => ctx.revert();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isStatic, from, delay, duration, start]);

  return (
    <Tag
      ref={rootRef}
      className={["relative", className].filter(Boolean).join(" ")}
      data-ink-reveal=""
      {...(isStatic ? { "data-static": "true", "data-revealed": "true" } : {})}
      {...rest}
    >
      {children}
    </Tag>
  );
}

export default InkReveal;

