1	// verify.mjs — route-driven assertion suite (v0).
2	//
3	// Boots playwright-core against the running dev server (:5173) and asserts the
4	// invariants that must hold on every build. v0 targets the CURRENT single-page
5	// site; sprints extend ROUTES + add route-aware checks via the check() harness.
6	//
7	// Usage:
8	//   node scripts/qa/verify.mjs               full suite, all ROUTES
9	//   node scripts/qa/verify.mjs --route=/     restrict to one route
10	//   node scripts/qa/verify.mjs --skippreload pass ?skippreload to every load
11	//
12	// Exit 0 only if every check passes; non-zero with a failure list otherwise.
13	import fs from "fs";
14	import { chromium } from "playwright-core";
15	import { ROUTES, DEV_URL, resolveChrome, parseArgs } from "./routes.mjs";
16	
17	// axe-core source, injected per page for the a11y/contrast audit (WCAG 2 A+AA).
18	const AXE_SOURCE = fs.readFileSync(
19	  new URL("../../node_modules/axe-core/axe.min.js", import.meta.url),
20	  "utf8"
21	);
22	
23	const args = parseArgs();
24	const SKIP = args.skippreload ? "skippreload" : "";
25	const onlyRoute = args.route || null;
26	
27	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
28	
29	// ---- check() harness -------------------------------------------------------
30	const results = [];
31	function check(name, ok, info = "") {
32	  results.push({ name, ok: !!ok, info });
33	  console.log(`${ok ? "PASS" : "FAIL"} ${name}${info ? `  ${info}` : ""}`);
34	}
35	
36	// Any of these fetched while reduced-motion / mobile / a no-GL route is active
37	// is a chunk-gating leak (scar #10 + perf budget). Matches Vite dep-optimized
38	// paths and any future manual GL chunk names.
39	const GL_CHUNKS =
40	  /node_modules\/\.vite\/deps\/(three|@react-three|postprocessing)|node_modules\/(three|@react-three|postprocessing)|\b(three|drei|HeroCanvas|GLStage|webgl|PipelineScene|[A-Za-z]*Scene)[-.][\w]+\.js/i;
41	
42	// S07 — the /work locked facts (PROTOCOL §8; sprint-07 §5), asserted VERBATIM.
43	// Desktop asserts them post-scroll (CountStrike rewinds at mount and commits on
44	// strike); reduced/mobile assert them immediately (static tier ships finals).
45	const WORK_NAMES = [
46	  "Manufacturing", "Legal Services", "Customs Broking", "Financial Technology",
47	  "Enterprise Management Transformation", "Real Estate Marketing",
48	  "HR Tech - First Hires", "Codebase Migration Assistant", "VIP Assistance",
49	];
50	const WORK_STATS = [
51	  "98% QC accuracy", "10x throughput", "99.3% classification accuracy",
52	  "Real-time fraud detection", "60+ processes automated",
53	  "240% listing exposure increase", "90% screening automation",
54	  "Full migration documentation", "92% task automation rate",
55	];
56	const WORK_RESULTS = [
57	  "98% defect-free output", "87% cost reduction", "72% faster clearance",
58	  "94% reduction in manual reconciliation", "3.2x operational efficiency",
59	  "3.8x inbound lead uplift", "74% faster time-to-hire",
60	  "80% technical debt reduction", "5.5hrs/day reclaimed per exec",
61	];
62	const WORK_CASES = [
63	  "First-Contact Agentic Legal Document Generator",
64	  "Local Agentic AI-Based Data Analyst for SMEs",
65	  "4-6 hours", "under 10 minutes",
66	];
67	
68	// Draw-call measurement: composer passes are only counted with autoReset off,
69	// accumulated across ~10 ticks then averaged (autoReset-on reports just the
70	// final screen-quad pass == 1). Returns -1 when no GL context (window.__gl).
71	async function measureDrawCalls(page) {
72	  return page.evaluate(
73	    () =>
74	      new Promise((res) => {
75	        const gl = window.__gl;
76	        if (!gl) return res(-1);
77	        gl.info.autoReset = false;
78	        gl.info.reset();
79	        if (window.__frame) window.__frame.needsFrames = 30;
80	        let ticks = 0;
81	        const tick = () => {
82	          if (++ticks < 10) return requestAnimationFrame(tick);
83	          const avg = Math.round(gl.info.render.calls / ticks);
84	          gl.info.autoReset = true;
85	          res(avg);
86	        };
87	        requestAnimationFrame(tick);
88	      })
89	  );
90	}
91	
92	// ScrollTrigger count, or -1 when the page hasn't exposed window.__stCount yet
93	// (current site does not). Callers skip gracefully on -1.
94	function stCount(page) {
95	  return page.evaluate(() => (window.__stCount ? window.__stCount() : -1));
96	}
97	
98	const EXEC = await resolveChrome();
99	const browser = await chromium.launch({ executablePath: EXEC, headless: true });
100	
101	const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
102	// "/lab" is not a ROUTES entry (dev-only bench) — --route=/lab runs just the
103	// S04 lab suite below.
104	if (routes.length === 0 && onlyRoute !== "/lab") {
105	  console.error(`No ROUTES match --route=${onlyRoute}`);
106	  process.exit(2);
107	}
108	
109	for (const route of routes) {
110	  const url = DEV_URL + route.path + (SKIP ? (route.path.includes("?") ? "&" : "?") + SKIP : "");
111	
112	  // ---- DESKTOP pass: load clean, audit links/integrations, GL on showpiece --
113	  {
114	    const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
115	    const consoleErrors = [];
116	    const pageErrors = [];
117	    const requests = [];
118	    page.on("console", (m) => m.type() === "error" && consoleErrors.push(m.text().slice(0, 300)));
119	    page.on("pageerror", (e) => pageErrors.push(String(e).slice(0, 300)));
120	    page.on("request", (r) => requests.push(r.url()));
121	
122	    let emailjsReq = null;
123	    await page.route("**/api.emailjs.com/**", (r) => {
124	      const req = r.request();
