127	      emailjsReq = { url: req.url(), method: req.method(), post: req.postData() || "" };
128	      r.fulfill({ status: 200, body: "OK" });
129	    });
130	
131	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
132	    await sleep(3500);
133	
134	    const tag = `[${route.name}]`;
135	
136	    // Route mounts its OWN stub (not the catch-all NotFound, not another page).
137	    // Asserted by the route's owned section ids being present AND the 404 marker
138	    // being absent. This is the per-route mount + deep-reload SPA-fallback proof:
139	    // we navigated directly to `url` (e.g. /work) and the real route mounted.
140	    const mount = await page.evaluate((ids) => ({
141	      ownedPresent: ids.filter((id) => !!document.getElementById(id)).length,
142	      ownedTotal: ids.length,
143	      isNotFound: !!document.getElementById("not-found"),
144	    }), route.ownedIds || []);
145	    check(
146	      `${tag} route mounts own stub (deep-reload SPA fallback)`,
147	      mount.ownedTotal > 0 && mount.ownedPresent === mount.ownedTotal && !mount.isNotFound,
148	      `(${mount.ownedPresent}/${mount.ownedTotal} owned ids, notFound=${mount.isNotFound})`
149	    );
150	
151	    // Nav links present.
152	    const navCount = await page.evaluate(
153	      () => document.querySelectorAll("nav a, nav button").length
154	    );
155	    check(`${tag} nav links present`, navCount >= 5, `(${navCount})`);
156	
157	    // Link / integration audit.
158	    const links = await page.evaluate(() => ({
159	      linkedinMembers: document.querySelectorAll('a[href*="linkedin.com/in/"]').length,
160	      linkedinCompany: document.querySelectorAll('a[href*="linkedin.com/company/"]').length,
161	      calendly: document.querySelectorAll('a[href*="calendly.com/sachmeet-kartar/30min"]').length,
162	      mailto: document.querySelectorAll('a[href="mailto:hello@kartar.ai"]').length,
163	      sender:
164	        !!document.querySelector('[data-sender-form-id]') ||
165	        !!document.querySelector('#sender-form'),
166	      fields: {
167	        from_name: !!document.querySelector('[name="from_name"]'),
