169	        from_phone: !!document.querySelector('[name="from_phone"]'),
170	        message: !!document.querySelector('[name="message"]'),
171	      },
172	    }));
173	    // Per-route INTEGRATION expectations (route.expect, from routes.mjs). The
174	    // single page is now split across 4 routes, so the contract is route-aware:
175	    // the 18 team LinkedIn links live only on the `team` route; the EmailJS form
176	    // only on the `contactForm` route; footer integrations + a Calendly CTA on
177	    // every route. facts_check.mjs still asserts the FULL contract site-wide.
178	    const exp = route.expect || {};
179	    if (exp.team) {
180	      check(`${tag} 18 LinkedIn member links`, links.linkedinMembers === 18, `(${links.linkedinMembers})`);
181	    }
182	    if (exp.companyLinked) {
183	      check(`${tag} >=1 company LinkedIn`, links.linkedinCompany >= 1, `(${links.linkedinCompany})`);
184	    }
185	    const calMin = exp.calendlyMin ?? 3;
186	    check(`${tag} >=${calMin} Calendly links`, links.calendly >= calMin, `(${links.calendly})`);
187	    if (exp.mailto) {
188	      check(`${tag} mailto hello@kartar.ai`, links.mailto >= 1);
189	    }
190	    if (exp.senderMount) {
191	      check(`${tag} Sender form mount present`, links.sender);
192	    }
193	    if (exp.contactForm) {
194	      check(
195	        `${tag} EmailJS fields present`,
196	        links.fields.from_name && links.fields.from_email && links.fields.from_phone && links.fields.message,
197	        `(name=${links.fields.from_name} email=${links.fields.from_email} phone=${links.fields.from_phone} msg=${links.fields.message})`
198	      );
199	    }
200	
201	    // EmailJS stub-submit: fill + submit, assert the request is formed with the
202	    // right service/template ids and the success text appears. Never sent — the
203	    // api.emailjs.com route is intercepted and fulfilled with OK.
204	    const hasContact = await page.evaluate(() => !!document.querySelector('form [name="from_name"]'));
205	    if (hasContact) {
206	      await page.evaluate(() => {
207	        const el = document.querySelector('form [name="from_name"]')?.closest("section") || document.querySelector("#contact");
208	        if (!el) return;
