235	      );
236	      check(
237	        `${tag} EmailJS template_2l3bp6f in request`,
238	        post.includes("template_2l3bp6f"),
239	        post ? "" : "(no post body captured)"
240	      );
241	      const success = await page.evaluate(() =>
242	        document.body.innerText.includes("Message sent. We'll get back to you within 24 hours.")
243	      );
