271	      stCountFn: typeof window.__stCount === "function",
272	      preloaderDone: window.__preloaderDone === true,
273	    }));
274	    check(`${tag} window.__lenis exposed (has scrollTo)`, backbone.lenis);
275	    check(`${tag} window.__stCount is a function`, backbone.stCountFn);
276	    check(`${tag} preloaderDone fired`, backbone.preloaderDone);
277	
278	    // ---- S05 chrome suite: navbar/footer/cursor/seam/newsletter ------------
279	    const chrome = await page.evaluate(() => {
280	      const hrefs = ["/", "/work", "/studio", "/contact"];
