324	      return {
325	        ok: issued && rect.top < window.innerHeight && rect.bottom > 0,
326	        why: `top=${Math.round(rect.top)}`,
327	      };
328	    });
329	    check(`${tag} goToNewsletter lands viewport on #newsletter`, reach.ok, `(${reach.why})`);
330	
331	    // ---- S06 home suite: composed Home, showpiece mounts, facts, CTA -------
332	    if (route.path === "/") {
333	      const home = await page.evaluate(() => {
334	        const text = document.body.textContent;
335	        const probe = (sel) => {
336	          const el = document.querySelector(sel);
337	          if (!el) return null;
338	          return {
339	            rel: getComputedStyle(el).position === "relative",
340	            w: el.offsetWidth,
341	            h: el.offsetHeight,
342	          };
343	        };
344	        const has = (arr) => arr.filter((s) => text.includes(s)).length;
345	        const poster = document.querySelector('[data-showpiece="hero"] [data-hero-poster]');
346	        return {
347	          hero: probe('[data-showpiece="hero"]'),
348	          heroPoster: !!poster && poster.childElementCount > 0,
349	          pipe: probe('[data-showpiece="pipeline"]'),
350	          pipeFallback: !!document.querySelector('[data-showpiece="pipeline"] [data-pipeline-fallback]'),
351	          stages: has(["Read", "Ground", "Reason", "Classify", "Cite"]),
352	          numbers: has(["8471.30", "₹2,41,800", "BCD 0%", "IGST 18%", "duty payable ₹0"]),
353	          industries: has(["Logistics", "Legal Tech", "Healthcare", "Finance", "Agriculture", "E-commerce", "Manufacturing", "Education"]),
354	          services: has(["Agentic AI Workflows", "Vertical SaaS Products", "AI Strategy & Scoping"]),
355	          testimonials: has(["CTO, Fintech Startup", "Operations Head, Logistics Co.", "Founder, Legal Tech Startup"]),
356	          heroHeadline:
357	            text.includes("Some industries haven't changed in 30 years.") &&
358	            text.includes("We're changing them now."),
359	          trustBar: has(["Pilot to production in weeks", "Services + Products", "Indian-first, not localised", "Timeline", "What we build", "Approach"]),
360	          heroCalendly: !!document.querySelector('#hero a[href*="calendly.com/sachmeet-kartar/30min"]'),
361	          heroToWork: !!document.querySelector('#hero a[href="/work"]'),
362	          ctaNewsletterBtn: !!document.querySelector('#cta a[href="#newsletter"]'),
363	          ctaCalendly: !!document.querySelector('#cta a[href*="calendly.com"]'),
364	        };
365	      });
