824	      counts.push(await stCount(page));
825	    }
826	    // S06 note: Home now carries once:true strike triggers that self-kill on a
827	    // lifecycle (not page-load) clock, so the count is steady-state-dependent.
828	    // The leak invariant: identical counts across identically-timed cycles (a
829	    // leak compounds per cycle) AND zero orphaned triggers (a leaked trigger
830	    // points at a detached element). Baseline equality was the stub-era check.
831	    check(
832	      "[backbone] zero trigger leak across 3 route cycles",
833	      counts[0] > 0 && counts.every((c) => c === counts[0]) && Math.abs(counts[0] - baseline) <= 3,
