    check("[lab] desktop: motion tier active (zero static fallbacks)", tier.statics === 0, `(${tier.statics})`);
    check("[lab] desktop: pinned scenes mounted (axis-rail + scrub-scene)", tier.pinSpacers >= 2, `(${tier.pinSpacers} pin-spacers)`);
    check("[lab] desktop: magnetic cursor mounted", tier.cursor);

    await labWalk(page);
    await sleep(900);

    const settled = await page.evaluate(() => {
      const ink = document.querySelector('[data-lab="ink-reveal"] [data-ink-reveal]');
      const split = document.querySelector('[data-lab="split-lines"] [data-split-lines]');
