    check("[lab] CountStrike 99.3% committed", settled.counts.some((t) => t.includes("99.3")), `(${settled.counts.join(" | ")})`);
    check("[lab] ScrubScene progress committed to 1.000", settled.readout === "1.000", `(${settled.readout})`);
    check("[lab] AxisRail latched end state (scar #5)", settled.railLatched === "end", `(${settled.railLatched})`);

