    check("[lab] mobile: zero pins", m.pinSpacers === 0, `(${m.pinSpacers})`);
    check("[lab] mobile: no custom cursor (coarse pointer)", !m.cursor);
    check(
      "[lab] mobile: CountStrike final numbers immediate",
      m.counts.some((t) => t.includes("2,41,800")),
      `(${m.counts.join(" | ")})`
    );
    check("[lab] mobile: content present", m.hasText);
    check("[lab] mobile: zero console errors", consoleErrors.length === 0, consoleErrors[0] || "");
    await page.close();
  }
}

await browser.close();

const fails = results.filter((r) => !r.ok);
console.log(`\n${results.length - fails.length}/${results.length} checks passed`);
if (fails.length) {
  console.log("\nFAILURES:");
  for (const f of fails) console.log(`  - ${f.name}${f.info ? `  ${f.info}` : ""}`);
}
process.exit(fails.length ? 1 : 0);

