1	// walkthrough.mjs — signature-moment screenshots per route, desktop + mobile.
2	//
3	// Loops ROUTES. For each route captures top / mid-scrub / bottom screenshots at
4	// desktop (1440x900) and mobile (390x844) to /tmp/shots/<tag>/<route>-<view>-NN.png.
5	// On routes with a `showpiece` selector, measures per-frame draw calls (composer
6	// passes accumulated with autoReset off). Tallies console errors; exits non-zero
7	// if any route logged a console error or pageerror.
8	//
9	// Usage:
10	//   node scripts/qa/walkthrough.mjs                 tag = "manual"
11	//   node scripts/qa/walkthrough.mjs --tag=sprint-06
12	//   node scripts/qa/walkthrough.mjs --route=/       restrict to one route
13	import { chromium } from "playwright-core";
14	import fs from "fs";
15	import path from "path";
16	import { ROUTES, DEV_URL, SHOTS_DIR, resolveChrome, parseArgs } from "./routes.mjs";
17	
18	const args = parseArgs();
19	const TAG = args.tag || "manual";
20	const onlyRoute = args.route || null;
21	const OUT = SHOTS_DIR(TAG);
22	fs.mkdirSync(OUT, { recursive: true });
23	
24	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
25	
26	async function measureDrawCalls(page) {
27	  return page.evaluate(
28	    () =>
29	      new Promise((res) => {
30	        const gl = window.__gl;
31	        if (!gl) return res(-1);
32	        gl.info.autoReset = false;
33	        gl.info.reset();
34	        if (window.__frame) window.__frame.needsFrames = 30;
35	        let ticks = 0;
36	        const tick = () => {
37	          if (++ticks < 10) return requestAnimationFrame(tick);
38	          const avg = Math.round(gl.info.render.calls / ticks);
39	          gl.info.autoReset = true;
40	          res(avg);
41	        };
42	        requestAnimationFrame(tick);
43	      })
44	  );
45	}
46	
47	// Scroll to a fraction of total scrollable height (Lenis-aware) and settle.
48	async function jumpFrac(page, frac, settle = 1800) {
49	  await page.evaluate((f) => {
50	    const max = document.documentElement.scrollHeight - window.innerHeight;
51	    const y = Math.max(0, Math.round(max * f));
52	    if (window.__lenis) window.__lenis.scrollTo(y, { immediate: true });
53	    else window.scrollTo(0, y);
54	    if (window.__snapCam) window.__snapCam();
55	  }, frac);
56	  await sleep(settle);
57	}
58	
59	const EXEC = await resolveChrome();
60	const browser = await chromium.launch({ executablePath: EXEC, headless: true });
61	
62	const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
63	let totalErrors = 0;
64	
65	// Preloader-first frame (S03): fresh context, NO skippreload, catch the veil
66	// mid-count before it lifts.
67	if (!onlyRoute || onlyRoute === "/") {
68	  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
69	  await page.goto(DEV_URL + "/", { waitUntil: "load", timeout: 60000 });
70	  try {
71	    await page.waitForSelector("[data-preloader]", { timeout: 5000 });
72	    await sleep(500); // mid-assemble: words landed, counter running
73	  } catch {
74	    console.log("  WARN: preloader veil not seen (already done?)");
75	  }
76	  await page.screenshot({ path: path.join(OUT, "home-desktop-preloader-first.png") });
77	  console.log("shot: home-desktop-preloader-first");
78	  await page.close();
79	}
80	
81	const VIEWS = [
82	  { view: "desktop", viewport: { width: 1440, height: 900 }, opts: {} },
83	  { view: "mobile", viewport: { width: 390, height: 844 }, opts: { hasTouch: true } },
84	];
85	
86	for (const route of routes) {
87	  const url = `${DEV_URL}${route.path}${route.path.includes("?") ? "&" : "?"}skippreload`;
88	
89	  for (const { view, viewport, opts } of VIEWS) {
90	    const page = await browser.newPage({ viewport, ...opts });
91	    const errors = [];
92	    page.on("console", (m) => m.type() === "error" && errors.push(m.text().slice(0, 300)));
93	    page.on("pageerror", (e) => errors.push("PAGEERROR: " + String(e).slice(0, 300)));
94	
95	    await page.goto(url, { waitUntil: "load", timeout: 60000 });
96	    await sleep(4500); // hero / GL fade / one-shot animations settle
97	
98	    const base = `${route.name}-${view}`;
99	    const fracs = [
100	      ["00-top", 0],
101	      ["01-quarter", 0.25],
102	      ["02-mid", 0.5],
103	      ["03-three-quarter", 0.75],
104	      ["04-bottom", 1],
105	    ];
106	    for (const [label, frac] of fracs) {
107	      await jumpFrac(page, frac);
108	      let note = "";
109	      if (route.showpiece && view === "desktop") {
110	        const onShowpiece = await page.evaluate((sel) => !!document.querySelector(sel), route.showpiece);
111	        if (onShowpiece) {
112	          const calls = await measureDrawCalls(page);
113	          note = `  drawCalls/frame≈${calls}`;
114	        }
115	      }
116	      await page.screenshot({ path: path.join(OUT, `${base}-${label}.png`) });
117	      console.log(`shot: ${base}-${label}${note}`);
118	    }
119	
120	    if (errors.length) {
121	      totalErrors += errors.length;
122	      console.log(`  CONSOLE ERRORS on ${base}: ${errors.slice(0, 10).join(" | ")}`);
123	    }
124	    await page.close();
125	  }
126	}
127	
128	// ---- S04: /lab proof bench frames (dev-only route; skipped if absent) ------
129	if (!onlyRoute || onlyRoute === "/lab") {
130	  const labUrl = `${DEV_URL}/lab?skippreload`;
131	  const probe = await browser.newPage({ viewport: { width: 1440, height: 900 } });
132	  let hasLab = false;
133	  try {
134	    await probe.goto(labUrl, { waitUntil: "load", timeout: 60000 });
135	    await sleep(1500);
136	    hasLab = await probe.evaluate(() => !!document.querySelector("[data-lab]"));
137	  } catch {
138	    hasLab = false;
139	  }
140	  await probe.close();
141	
142	  if (!hasLab) {
143	    console.log("  WARN: /lab not reachable (prod build or route missing) — lab frames skipped");
144	  } else {
145	    const fracs = [
146	      ["00-top", 0],
147	      ["01-quarter", 0.25],
148	      ["02-mid", 0.5],
149	      ["03-three-quarter", 0.75],
150	      ["04-bottom", 1],
151	    ];
152	    const passes = [
153	      { base: "lab-desktop", viewport: { width: 1440, height: 900 }, opts: {} },
154	      { base: "lab-mobile", viewport: { width: 390, height: 844 }, opts: { hasTouch: true } },
155	      { base: "lab-reduced", viewport: { width: 1440, height: 900 }, opts: { reducedMotion: "reduce" } },
156	    ];
157	    for (const { base, viewport, opts } of passes) {
158	      const page = await browser.newPage({ viewport, ...opts });
159	      const errors = [];
160	      page.on("console", (m) => m.type() === "error" && errors.push(m.text().slice(0, 300)));
161	      page.on("pageerror", (e) => errors.push("PAGEERROR: " + String(e).slice(0, 300)));
162	      await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
163	      await sleep(3500);
164	      for (const [label, frac] of fracs) {
165	        await jumpFrac(page, frac);
166	        await page.screenshot({ path: path.join(OUT, `${base}-${label}.png`) });
167	        console.log(`shot: ${base}-${label}`);
168	      }
169	      if (errors.length) {
170	        totalErrors += errors.length;
171	        console.log(`  CONSOLE ERRORS on ${base}: ${errors.slice(0, 10).join(" | ")}`);
172	      }
173	      await page.close();
174	    }
175	  }
176	}
177	
178	await browser.close();
179	console.log(`\nwalkthrough complete → ${OUT}`);
180	console.log(totalErrors ? `CONSOLE ERRORS: ${totalErrors}` : "CONSOLE ERRORS: none");
181	process.exit(totalErrors ? 1 : 0);
182

