import { ROUTES, DEV_URL, SHOTS_DIR, resolveChrome, parseArgs } from "./routes.mjs";

const args = parseArgs();
const TAG = args.tag || "manual";
const onlyRoute = args.route || null;
const OUT = SHOTS_DIR(TAG);
fs.mkdirSync(OUT, { recursive: true });

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function measureDrawCalls(page) {
  return page.evaluate(
    () =>
      new Promise((res) => {
        const gl = window.__gl;
        if (!gl) return res(-1);
        gl.info.autoReset = false;
        gl.info.reset();
        if (window.__frame) window.__frame.needsFrames = 30;
        let ticks = 0;
        const tick = () => {
          if (++ticks < 10) return requestAnimationFrame(tick);
          const avg = Math.round(gl.info.render.calls / ticks);
          gl.info.autoReset = true;
          res(avg);
        };
        requestAnimationFrame(tick);
      })
  );
}

// Scroll to a fraction of total scrollable height (Lenis-aware) and settle.
async function jumpFrac(page, frac, settle = 1800) {
  await page.evaluate((f) => {
    const max = document.documentElement.scrollHeight - window.innerHeight;
    const y = Math.max(0, Math.round(max * f));
    if (window.__lenis) window.__lenis.scrollTo(y, { immediate: true });
    else window.scrollTo(0, y);
    if (window.__snapCam) window.__snapCam();
  }, frac);
  await sleep(settle);
}

const EXEC = await resolveChrome();
const browser = await chromium.launch({ executablePath: EXEC, headless: true });

const routes = ROUTES.filter((r) => !onlyRoute || r.path === onlyRoute);
let totalErrors = 0;

// Preloader-first frame (S03): fresh context, NO skippreload, catch the veil
// mid-count before it lifts.
if (!onlyRoute || onlyRoute === "/") {
  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
  await page.goto(DEV_URL + "/", { waitUntil: "load", timeout: 60000 });
  try {
    await page.waitForSelector("[data-preloader]", { timeout: 5000 });
    await sleep(500); // mid-assemble: words landed, counter running
  } catch {
    console.log("  WARN: preloader veil not seen (already done?)");
  }
  await page.screenshot({ path: path.join(OUT, "home-desktop-preloader-first.png") });
  console.log("shot: home-desktop-preloader-first");
  await page.close();
}

const VIEWS = [
  { view: "desktop", viewport: { width: 1440, height: 900 }, opts: {} },
  { view: "mobile", viewport: { width: 390, height: 844 }, opts: { hasTouch: true } },
];

for (const route of routes) {
  const url = `${DEV_URL}${route.path}${route.path.includes("?") ? "&" : "?"}skippreload`;

  for (const { view, viewport, opts } of VIEWS) {
    const page = await browser.newPage({ viewport, ...opts });
    const errors = [];
    page.on("console", (m) => m.type() === "error" && errors.push(m.text().slice(0, 300)));
    page.on("pageerror", (e) => errors.push("PAGEERROR: " + String(e).slice(0, 300)));

    await page.goto(url, { waitUntil: "load", timeout: 60000 });
    await sleep(4500); // hero / GL fade / one-shot animations settle

    const base = `${route.name}-${view}`;
    const fracs = [
      ["00-top", 0],
      ["01-quarter", 0.25],
      ["02-mid", 0.5],
      ["03-three-quarter", 0.75],
      ["04-bottom", 1],
    ];
    for (const [label, frac] of fracs) {
      await jumpFrac(page, frac);
      let note = "";
      if (route.showpiece && view === "desktop") {
        const onShowpiece = await page.evaluate((sel) => !!document.querySelector(sel), route.showpiece);
        if (onShowpiece) {
          const calls = await measureDrawCalls(page);
          note = `  drawCalls/frame≈${calls}`;
        }
      }
      await page.screenshot({ path: path.join(OUT, `${base}-${label}.png`) });
      console.log(`shot: ${base}-${label}${note}`);
    }

    if (errors.length) {
      totalErrors += errors.length;
      console.log(`  CONSOLE ERRORS on ${base}: ${errors.slice(0, 10).join(" | ")}`);
    }
    await page.close();
  }
}

// ---- S04: /lab proof bench frames (dev-only route; skipped if absent) ------
if (!onlyRoute || onlyRoute === "/lab") {
  const labUrl = `${DEV_URL}/lab?skippreload`;
  const probe = await browser.newPage({ viewport: { width: 1440, height: 900 } });
  let hasLab = false;
  try {
    await probe.goto(labUrl, { waitUntil: "load", timeout: 60000 });
    await sleep(1500);
    hasLab = await probe.evaluate(() => !!document.querySelector("[data-lab]"));
  } catch {
    hasLab = false;
  }
  await probe.close();

  if (!hasLab) {
    console.log("  WARN: /lab not reachable (prod build or route missing) — lab frames skipped");
  } else {
    const fracs = [
      ["00-top", 0],
      ["01-quarter", 0.25],
      ["02-mid", 0.5],
      ["03-three-quarter", 0.75],
      ["04-bottom", 1],
    ];
    const passes = [
      { base: "lab-desktop", viewport: { width: 1440, height: 900 }, opts: {} },
      { base: "lab-mobile", viewport: { width: 390, height: 844 }, opts: { hasTouch: true } },
      { base: "lab-reduced", viewport: { width: 1440, height: 900 }, opts: { reducedMotion: "reduce" } },
    ];
    for (const { base, viewport, opts } of passes) {
      const page = await browser.newPage({ viewport, ...opts });
      const errors = [];
      page.on("console", (m) => m.type() === "error" && errors.push(m.text().slice(0, 300)));
      page.on("pageerror", (e) => errors.push("PAGEERROR: " + String(e).slice(0, 300)));
      await page.goto(labUrl, { waitUntil: "load", timeout: 60000 });
      await sleep(3500);
      for (const [label, frac] of fracs) {
        await jumpFrac(page, frac);
        await page.screenshot({ path: path.join(OUT, `${base}-${label}.png`) });
        console.log(`shot: ${base}-${label}`);
      }
      if (errors.length) {
        totalErrors += errors.length;
        console.log(`  CONSOLE ERRORS on ${base}: ${errors.slice(0, 10).join(" | ")}`);
      }
      await page.close();
    }
  }
}

await browser.close();
console.log(`\nwalkthrough complete → ${OUT}`);
console.log(totalErrors ? `CONSOLE ERRORS: ${totalErrors}` : "CONSOLE ERRORS: none");
process.exit(totalErrors ? 1 : 0);

